import{c as t,Q as a,j as s,m as o}from"./chunks/framework.BPKcPtvA.js";const r="/assets/alpha_bracket.C5mFxpdJ.png",y=JSON.parse('{"title":"Main Bracket (Playoffs)","description":"","frontmatter":{},"headers":[],"relativePath":"playoffs/bracket.md","filePath":"playoffs/bracket.md","lastUpdated":1778764647000}'),i={name:"playoffs/bracket.md"};function n(l,e,d,h,c,p){return a(),s("div",null,[...e[0]||(e[0]=[o('<h1 id="main-bracket-playoffs" tabindex="-1">Main Bracket (Playoffs) <a class="header-anchor" href="#main-bracket-playoffs" aria-label="Permalink to &quot;Main Bracket (Playoffs)&quot;">​</a></h1><p>The Main Bracket, also known as the <strong>Playoffs</strong>, is a four-day event.<br> It follows a 1v1 single-elimination format.</p><h2 id="seeding-system" tabindex="-1">Seeding System <a class="header-anchor" href="#seeding-system" aria-label="Permalink to &quot;Seeding System&quot;">​</a></h2><p>At the end of the season, the 12 players with the most <strong><em>phase points</em></strong> will be automatically invited and seeded 1 through 12 accordingly. Four additional players, seeded 13 through 16, will qualify through the <a href="./last_chance_qualifiers">Last-Chance Qualifiers</a>. Learn more about the phase point system <a href="./phase_point">here</a>.</p><p>Players seeded 1 through 7 will each choose their opponent from a pool of 8 players, which includes players seeded 9 through 12 and the 4 players who qualified through the <a href="./last_chance_qualifiers">Last-Chance Qualifiers</a>. The final unchosen player will be automatically assigned to the player seeded 8.</p><h2 id="rounds" tabindex="-1">Rounds <a class="header-anchor" href="#rounds" aria-label="Permalink to &quot;Rounds&quot;">​</a></h2><p>The bracket consists of four rounds. In each round, both players will play the same seed simultaneously, and the player who completes the game first will take the seed.</p><p>Match formats for each round are as follows:</p><ul><li>Round of 16: First to take <strong>3</strong> seeds (<strong>Best of 5</strong>)</li><li>Quarterfinals: First to take <strong>3</strong> seeds (<strong>Best of 5</strong>)</li><li>Semifinals: First to take <strong>3</strong> seeds (<strong>Best of 5</strong>)</li><li>3rd Place: First to take <strong>3</strong> seeds (<strong>Best of 5</strong>)</li><li>Grand Finals: First to take <strong>4</strong> seeds (<strong>Best of 7</strong>)</li></ul><p>As shown in the bracket below, all matchups after the Round of 16 are automatically determined based on the fixed structure. The bracket progresses without any further opponent selection.</p><p><img src="'+r+'" alt="Bracket Image"></p><h2 id="seed-type-pick" tabindex="-1">Seed Type Pick <a class="header-anchor" href="#seed-type-pick" aria-label="Permalink to &quot;Seed Type Pick&quot;">​</a></h2><p>In the bracket, players can choose from the same 5 seed types used in the MCSR Ranked Seed Filter. Players can strategically decide which seeds to play.</p><p>For more information on the seed types, check <a href="/gameplay/seed#overworld-types">here</a>.</p><h3 id="pick" tabindex="-1">Pick <a class="header-anchor" href="#pick" aria-label="Permalink to &quot;Pick&quot;">​</a></h3><p>Before starting the first seed, the top-seeded player chooses the first seed type. After each seed, the loser of the previous seed picks the next seed type. The loser cannot pick the most recently played seed type, or any seed type they have already won on.</p><h3 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h3><p>To summarize, the seed ban and pick process is as follows:</p><ul><li>First seed pick: Higher-seeded player</li><li>Next seed picks: Loser of the previous seed, who cannot pick the previous seed type or any seed type they have already won on. <ul><li>e.g. Higher-seeded Player <code>A</code> picked the Village seed type for the first seed and won the seed, but lost the second seed which was a Shipwreck. Player <code>A</code> can pick any seed type except those two types.<sup class="footnote-ref"><a href="#fn1" id="fnref1">[1]</a></sup></li><li>In other words, a player can pick a seed type twice, as long as they lost in the first instance of it being played, and it is not the last played seed type.</li></ul></li></ul><hr class="footnotes-sep"><section class="footnotes"><ol class="footnotes-list"><li id="fn1" class="footnote-item"><p>So, Buried Treasure, Desert Temple and Ruined Portal <a href="#fnref1" class="footnote-backref">↩︎</a></p></li></ol></section>',21)])])}const u=t(i,[["render",n]]);export{y as __pageData,u as default};
